const parseVerifySetting = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return String(value);
};

const quoteIdent = (v) => '"' + String(v).replace(/"/g, '""') + '"';

const req = msg.energyRequest || {};
if (!req.start_ts || !req.end_ts) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts and end_ts are required' };
    return [null, msg];
}

const accessToken = msg.trinoAuth && msg.trinoAuth.access_token;
if (!accessToken) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Trino authentication failed' };
    return [null, msg];
}

const host = env.get('AI_INSIGHT_TRINO__HOST') || 'localhost';
const port = Number(env.get('AI_INSIGHT_TRINO__PORT') || 8080);
const scheme = env.get('AI_INSIGHT_TRINO__HTTP_SCHEME') || 'http';
const user = env.get('AI_INSIGHT_TRINO__USER') || 'trino';
const catalog = env.get('AI_INSIGHT_TRINO__CATALOG') || 'hive';
const schema = env.get('AI_INSIGHT_TRINO__TARGET_SCHEMA') || 'gold';

const tableNetGrid = env.get('AI_INSIGHT_TRINO__TABLE_NET_GRID_HOURLY') || 'net_grid_hourly';
const tableWeather = env.get('AI_INSIGHT_TRINO__TABLE_WEATHER_HOURLY') || 'weather_hourly';
const tableCostDaily = env.get('AI_INSIGHT_TRINO__TABLE_ENERGY_COST_DAILY') || 'energy_cost_daily';
const tablePvDaily = env.get('AI_INSIGHT_TRINO__TABLE_PV_SELF_CONSUMPTION_DAILY') || 'pv_self_consumption_daily';

const startTs = req.start_ts;
const endTs = req.end_ts;
const trinoVerifySetting = parseVerifySetting(env.get('AI_INSIGHT_TRINO__VERIFY'), true);

const hourlySql = [
    'SELECT',
    '  grid.hour,',
    '  grid.avg_consumption_kw,',
    '  grid.avg_generation_kw,',
    '  grid.net_grid_kw,',
    '  grid.avg_price_eur_per_kwh,',
    '  grid.estimated_hourly_cost_eur,',
    '  weather.avg_temperature_c,',
    '  weather.avg_irradiance_w_m2,',
    '  weather.avg_humidity_pct,',
    '  weather.avg_wind_speed_ms,',
    '  weather.avg_cloud_cover_pct',
    `FROM ${quoteIdent(schema)}.${quoteIdent(tableNetGrid)} AS grid`,
    `LEFT JOIN ${quoteIdent(schema)}.${quoteIdent(tableWeather)} AS weather`,
    'ON grid.hour = weather.hour',
    `WHERE grid.hour >= from_iso8601_timestamp('${startTs}')`,
    `  AND grid.hour < from_iso8601_timestamp('${endTs}')`,
    'ORDER BY grid.hour'
].join('\n');

const dailyCostSql = [
    'SELECT',
    '  cost_date,',
    '  total_consumption_kw,',
    '  avg_cost_per_reading_eur,',
    '  peak_consumption_kw,',
    '  offpeak_consumption_kw,',
    '  avg_peak_price_eur,',
    '  avg_offpeak_price_eur,',
    '  reading_count',
    `FROM ${quoteIdent(schema)}.${quoteIdent(tableCostDaily)}`,
    `WHERE cost_date >= CAST(from_iso8601_timestamp('${startTs}') AS DATE)`,
    `  AND cost_date < CAST(from_iso8601_timestamp('${endTs}') AS DATE)`,
    'ORDER BY cost_date'
].join('\n');

const dailyPvSql = [
    'SELECT',
    '  sc_date,',
    '  total_consumption_kw,',
    '  total_generation_kw,',
    '  self_consumed_kw,',
    '  exported_kw,',
    '  imported_kw,',
    '  self_consumption_ratio,',
    '  autarky_ratio',
    `FROM ${quoteIdent(schema)}.${quoteIdent(tablePvDaily)}`,
    `WHERE sc_date >= CAST(from_iso8601_timestamp('${startTs}') AS DATE)`,
    `  AND sc_date < CAST(from_iso8601_timestamp('${endTs}') AS DATE)`,
    'ORDER BY sc_date'
].join('\n');

const statementUrl = `${scheme}://${host}:${port}/v1/statement`;
const statementHeaders = {
    'Authorization': `Bearer ${accessToken}`,
    'X-Trino-User': user,
    'X-Trino-Catalog': catalog,
    'X-Trino-Schema': schema,
    'Content-Type': 'text/plain; charset=utf-8',
};

msg._energyTrino = {
    queries: [
        { key: 'hourly', sql: hourlySql },
        { key: 'daily_cost', sql: dailyCostSql },
        { key: 'daily_pv', sql: dailyPvSql },
    ],
    currentIndex: 0,
    rowsByKey: {},
    columns: [],
    rows: [],
    statementUrl,
    statementHeaders,
    meta: {
        catalog,
        schema,
        tables: {
            table_net_grid_hourly: tableNetGrid,
            table_weather_hourly: tableWeather,
            table_energy_cost_daily: tableCostDaily,
            table_pv_self_consumption_daily: tablePvDaily,
        },
    },
    nextHeaders: {
        'Authorization': `Bearer ${accessToken}`,
        'X-Trino-User': user,
    },
};

const current = msg._energyTrino.queries[msg._energyTrino.currentIndex];
msg.method = 'POST';
msg.url = statementUrl;
msg.headers = Object.assign({}, statementHeaders);
msg.payload = current.sql;

if (trinoVerifySetting === false) {
    msg.rejectUnauthorized = false;
} else if (typeof trinoVerifySetting === 'string') {
    msg.rejectUnauthorized = false;
} else {
    msg.rejectUnauthorized = true;
}

return [msg, null];

const status = Number(msg.statusCode || 0);
if (status === 401 || status === 403 || status >= 400) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Upstream dependency failure while generating insight' };
    return [null, null, msg];
}

const state = msg._energyTrino || {};
const body = msg.payload || {};
if (!Array.isArray(state.columns)) state.columns = [];
if (!Array.isArray(state.rows)) state.rows = [];
if (!state.rowsByKey || typeof state.rowsByKey !== 'object') state.rowsByKey = {};

if (Array.isArray(body.columns) && body.columns.length > 0 && state.columns.length === 0) {
    state.columns = body.columns.map((c) => c.name);
}

const dataRows = Array.isArray(body.data) ? body.data : [];
for (const row of dataRows) {
    if (!Array.isArray(row)) continue;
    const mapped = {};
    for (let i = 0; i < state.columns.length; i += 1) {
        mapped[state.columns[i]] = row[i];
    }
    state.rows.push(mapped);
}

if (body.nextUri) {
    msg._energyTrino = state;
    msg.method = 'GET';
    msg.url = String(body.nextUri);
    msg.headers = Object.assign({}, state.nextHeaders || {});
    msg.payload = '';
    return [msg, null, null];
}

const queries = Array.isArray(state.queries) ? state.queries : [];
const idx = Number(state.currentIndex || 0);
const current = queries[idx];
if (!current || !current.key) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Upstream dependency failure while generating insight' };
    return [null, null, msg];
}

state.rowsByKey[current.key] = state.rows;
state.currentIndex = idx + 1;
state.columns = [];
state.rows = [];

if (state.currentIndex < queries.length) {
    const nextQuery = queries[state.currentIndex];
    msg._energyTrino = state;
    msg.method = 'POST';
    msg.url = String(state.statementUrl || '');
    msg.headers = Object.assign({}, state.statementHeaders || {});
    msg.payload = nextQuery.sql;
    return [msg, null, null];
}

msg._energyTrino = state;
msg.energyDataset = {
    hourly: Array.isArray(state.rowsByKey.hourly) ? state.rowsByKey.hourly : [],
    daily_cost: Array.isArray(state.rowsByKey.daily_cost) ? state.rowsByKey.daily_cost : [],
    daily_pv: Array.isArray(state.rowsByKey.daily_pv) ? state.rowsByKey.daily_pv : [],
};
msg.trinoQuery = {
    catalog: state.meta && state.meta.catalog,
    schema: state.meta && state.meta.schema,
    tables: state.meta && state.meta.tables,
    row_count: msg.energyDataset.hourly.length,
};

return [null, msg, null];

const uuidFromMathRandom = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : ((rand & 0x3) | 0x8);
    return value.toString(16);
});
const runtimeCrypto = global.get('crypto');
const makeOutputId = () => (runtimeCrypto && typeof runtimeCrypto.randomUUID === 'function') ? runtimeCrypto.randomUUID() : uuidFromMathRandom();

const toBool = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const toNumber = (value, fallback) => {
    if (value === undefined || value === null || typeof value === 'boolean') return fallback;
    if (typeof value === 'string' && value.trim() === '') return fallback;
    const n = Number(value);
    return Number.isFinite(n) ? n : fallback;
};

const round4 = (value) => {
    const n = Number(value);
    if (!Number.isFinite(n)) return null;
    return Number(n.toFixed(4));
};

const toDate = (value) => {
    if (value === undefined || value === null || value === '') return null;
    const raw = String(value).trim().replace(' UTC', 'Z').replace(' ', 'T');
    const d = new Date(raw);
    if (Number.isNaN(d.getTime())) return null;
    return d;
};

const toIsoLikePython = (value) => {
    const d = toDate(value);
    if (!d) return String(value);
    return d.toISOString().replace('.000Z', '+00:00');
};

const mean = (values) => {
    if (!Array.isArray(values) || values.length === 0) return null;
    return values.reduce((acc, item) => acc + item, 0) / values.length;
};

const trendDirection = (values, epsilon) => {
    if (!Array.isArray(values) || values.length < 2) {
        return { direction: 'stable', slope_per_step: 0.0 };
    }
    const points = values.length >= 24 ? values.slice(-24) : values;
    const slope = (points[points.length - 1] - points[0]) / Math.max(1, points.length - 1);
    const baseline = Math.max(Math.abs(points[0]), 1.0);
    const normalized = slope / baseline;
    let direction = 'stable';
    if (normalized > epsilon) direction = 'up';
    else if (normalized < -epsilon) direction = 'down';
    return { direction, slope_per_step: round4(slope) || 0.0 };
};

const dailyTrend = (values) => {
    if (!Array.isArray(values) || values.length < 2) return 'stable';
    const delta = values[values.length - 1] - values[0];
    if (delta > 0) return 'up';
    if (delta < 0) return 'down';
    return 'stable';
};

const sortObjectKeys = (source) => Object.keys(source || {}).sort().reduce((acc, key) => {
    acc[key] = source[key];
    return acc;
}, {});

const req = msg.energyRequest || {};
const access = msg.accessContext || {};
const includeData = !!req.include_data;
const alpha = toNumber(req.forecast_alpha, 0.6);
const epsilon = toNumber(req.trend_epsilon, 0.02);
const timezone = req.timezone || 'UTC';

const dataset = msg.energyDataset || {};
const hourlyRowsRaw = Array.isArray(dataset.hourly) ? dataset.hourly : [];
const dailyCostRows = Array.isArray(dataset.daily_cost) ? dataset.daily_cost : [];
const dailyPvRows = Array.isArray(dataset.daily_pv) ? dataset.daily_pv : [];

const hourlyRows = hourlyRowsRaw
    .map((row) => ({ row, ts: toDate(row.hour) }))
    .filter((item) => item.ts !== null)
    .sort((a, b) => a.ts.getTime() - b.ts.getTime());

const METRICS = ['avg_consumption_kw', 'net_grid_kw', 'estimated_hourly_cost_eur'];
const series = {};
const seasonalityBuckets = {};
for (const metric of METRICS) {
    series[metric] = [];
    seasonalityBuckets[metric] = {};
    for (let h = 0; h < 24; h += 1) {
        seasonalityBuckets[metric][String(h)] = [];
    }
}

for (const item of hourlyRows) {
    for (const metric of METRICS) {
        const value = toNumber(item.row[metric], NaN);
        if (!Number.isFinite(value)) continue;
        series[metric].push(value);
        const hourKey = String(item.ts.getUTCHours());
        seasonalityBuckets[metric][hourKey].push(value);
    }
}

const movingAverages = {};
const trendSignals = {};
const seasonalityPatterns = {};
const seasonalityMeans = {};
for (const metric of METRICS) {
    const values = series[metric];
    const ma6 = values.length >= 6 ? mean(values.slice(-6)) : null;
    const ma24 = values.length >= 24 ? mean(values.slice(-24)) : null;
    movingAverages[metric] = {
        ma_6h: ma6 === null ? null : round4(ma6),
        ma_24h: ma24 === null ? null : round4(ma24),
        latest_value: values.length === 0 ? null : round4(values[values.length - 1]),
    };
    trendSignals[metric] = trendDirection(values, epsilon);

    const perHour = {};
    const valsForMean = [];
    for (let h = 0; h < 24; h += 1) {
        const bucket = seasonalityBuckets[metric][String(h)] || [];
        const m = bucket.length === 0 ? null : round4(mean(bucket));
        perHour[String(h)] = m;
        if (m !== null) valsForMean.push(m);
    }
    seasonalityPatterns[metric] = perHour;
    seasonalityMeans[metric] = valsForMean.length === 0 ? 0.0 : mean(valsForMean);
}

const forecast24h = [];
const reference = hourlyRows.length === 0 ? null : hourlyRows[hourlyRows.length - 1].ts;
if (reference) {
    for (let step = 1; step <= 24; step += 1) {
        const pointTs = new Date(reference.getTime() + step * 60 * 60 * 1000);
        const point = { timestamp: pointTs.toISOString().replace('.000Z', '+00:00') };
        for (const metric of METRICS) {
            const values = series[metric];
            const recentLevel = values.length === 0 ? 0.0 : mean(values.slice(-24));
            const hourKey = String(pointTs.getUTCHours());
            const seasonal = seasonalityPatterns[metric][hourKey];
            const seasonalValue = seasonal === null ? seasonalityMeans[metric] : seasonal;
            const forecastValue = recentLevel + (alpha * (seasonalValue - seasonalityMeans[metric]));
            point[metric] = round4(forecastValue);
        }
        forecast24h.push(point);
    }
}

const confidenceNotes = [];
if (hourlyRows.length === 0) {
    confidenceNotes.push('No hourly rows available; forecast cannot be computed reliably.');
} else {
    for (const metric of METRICS) {
        const total = hourlyRows.length;
        const missing = total - series[metric].length;
        if (total > 0 && (missing / total) > 0.15) {
            confidenceNotes.push(`${metric}: elevated missingness (${missing}/${total}) lowers forecast confidence.`);
        }
    }
}
if (confidenceNotes.length === 0) {
    confidenceNotes.push('Recent history coverage is sufficient for deterministic baseline forecasting.');
}

const dailyCostValues = dailyCostRows.map((r) => toNumber(r.total_consumption_kw, NaN)).filter((v) => Number.isFinite(v));
const selfRatioValues = dailyPvRows.map((r) => toNumber(r.self_consumption_ratio, NaN)).filter((v) => Number.isFinite(v));
let dailyOverview = {
    daily_cost_points: dailyCostRows.length,
    daily_pv_points: dailyPvRows.length,
    consumption_trend_daily: dailyTrend(dailyCostValues),
    self_consumption_trend_daily: dailyTrend(selfRatioValues),
    source: 'daily_views',
};

if (req.daily_overview_strategy === 'fallback_hourly' && dailyCostRows.length === 0 && dailyPvRows.length === 0) {
    const byDay = {};
    for (const item of hourlyRows) {
        const key = item.ts.toISOString().slice(0, 10);
        if (!byDay[key]) byDay[key] = { consumption: [], generation: [] };
        const cons = toNumber(item.row.avg_consumption_kw, NaN);
        const gen = toNumber(item.row.avg_generation_kw, NaN);
        if (Number.isFinite(cons)) byDay[key].consumption.push(cons);
        if (Number.isFinite(gen)) byDay[key].generation.push(gen);
    }
    const dayKeys = Object.keys(byDay).sort();
    const dailyConsumption = [];
    const dailySelfRatio = [];
    for (const dayKey of dayKeys) {
        const consValues = byDay[dayKey].consumption;
        const genValues = byDay[dayKey].generation;
        if (consValues.length > 0) {
            dailyConsumption.push(consValues.reduce((a, b) => a + b, 0));
        }
        if (consValues.length > 0 && genValues.length > 0) {
            const consSum = consValues.reduce((a, b) => a + b, 0);
            const genSum = genValues.reduce((a, b) => a + b, 0);
            const ratio = genSum > 0 ? Math.min(consSum, genSum) / genSum : 0.0;
            dailySelfRatio.push(ratio);
        }
    }
    dailyOverview = {
        daily_cost_points: dailyConsumption.length,
        daily_pv_points: dailySelfRatio.length,
        consumption_trend_daily: dailyTrend(dailyConsumption),
        self_consumption_trend_daily: dailyTrend(dailySelfRatio),
        source: 'hourly_fallback',
    };
    confidenceNotes.push('Daily views were empty; daily_overview was estimated from hourly series fallback.');
}

const bounds = (rows, key) => {
    if (!Array.isArray(rows) || rows.length === 0) return { count: 0, first: null, last: null };
    const values = rows.map((r) => r[key]).filter((v) => v !== undefined && v !== null);
    if (values.length === 0) return { count: rows.length, first: null, last: null };
    const ordered = values.map((v) => String(v)).sort((a, b) => a.localeCompare(b));
    return {
        count: rows.length,
        first: toIsoLikePython(ordered[0]),
        last: toIsoLikePython(ordered[ordered.length - 1]),
    };
};

const hints = [...confidenceNotes];
if (forecast24h.length > 0) {
    hints.push('Forecast uses hourly seasonality plus recent-level adjustment baseline model.');
} else {
    hints.push('Forecast output is empty due to insufficient hourly history in selected window.');
}

const trendSignalsSorted = sortObjectKeys(trendSignals);
const movingAveragesSorted = sortObjectKeys(movingAverages);
const seasonalityPatternsSorted = sortObjectKeys(seasonalityPatterns);
const trackedMetricsSorted = Object.keys(trendSignalsSorted);

const context = {
    window: {
        start_ts: (req.start_ts || '').replace('.000Z', '+00:00'),
        end_ts: (req.end_ts || '').replace('.000Z', '+00:00'),
        timezone,
        rows_analyzed: hourlyRowsRaw.length,
    },
    trend_signals: trendSignalsSorted,
    moving_averages: movingAveragesSorted,
    seasonality_patterns: seasonalityPatternsSorted,
    forecast_24h: forecast24h,
    daily_overview: dailyOverview,
    data_availability: {
        hourly_net_grid_weather: bounds(hourlyRowsRaw, 'hour'),
        daily_cost: bounds(dailyCostRows, 'cost_date'),
        daily_pv_self_consumption: bounds(dailyPvRows, 'sc_date'),
    },
    narrative_hints: hints,
    summary: {
        forecast_points: forecast24h.length,
        tracked_metrics: trackedMetricsSorted,
        daily_cost_points: dailyOverview.daily_cost_points,
        daily_pv_points: dailyOverview.daily_pv_points,
    },
};

const fallbackOutput = {
    summary: `Fallback insight generated from deterministic analytics context: ${JSON.stringify(context.summary)}`,
    key_findings: hints.length > 0 ? hints.slice(0, 4) : ['No critical findings were detected for the requested interval.'],
    recommendations: [
        'Validate trend and forecast outputs against operational dashboards before publishing.',
        'Trigger a dashboard refresh once upstream LLM connectivity is restored.'
    ],
};

const cacheEnabled = toBool(env.get('AI_INSIGHT_CACHE__ENABLED'), false);
const cachePrefix = env.get('AI_INSIGHT_CACHE__KEY_PREFIX') || 'ai-insight:cache:v1';
const cacheKey = [
    cachePrefix,
    'energy-summary',
    access.agreement_id || 'unknown-agreement',
    access.asset_id || 'unknown-asset',
    req.start_ts || '',
    req.end_ts || '',
    timezone,
    String(alpha),
    String(epsilon),
    String(req.daily_overview_strategy || 'strict_daily'),
].join(':');
const cacheStore = global.get('aiInsightEnergySummaryCache') || {};
const reqHeaders = (msg.req && msg.req.headers) || {};
const rawCacheBypass = String(reqHeaders['x-insight-cache-bypass'] || reqHeaders['x-cache-bypass'] || '').trim().toLowerCase();
const cacheBypass = ['1', 'true', 'yes', 'on'].includes(rawCacheBypass);

const makeSuccessMsg = (result, llmUsed, llmModel, llmError) => {
    const outputId = makeOutputId();
    const timestamp = new Date().toISOString();
    const isDev = ['development', 'dev', 'local'].includes(String(env.get('AI_INSIGHT_SERVICE__ENVIRONMENT') || env.get('FACIS_ENV') || 'development').toLowerCase());
    msg.statusCode = 200;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = {
        insight_type: 'energy-summary',
        summary: result.summary,
        key_findings: result.key_findings,
        recommendations: result.recommendations,
        metadata: {
            output_id: outputId,
            llm_model: llmModel,
            timestamp,
            llm_used: llmUsed,
            agreement_id: access.agreement_id || 'unknown-agreement',
            asset_id: access.asset_id || 'unknown-asset',
            llm_error: isDev ? llmError : null,
        },
        data: includeData ? context : null,
    };
};

if (cacheEnabled && !cacheBypass && cacheStore[cacheKey]) {
    const cached = cacheStore[cacheKey];
    makeSuccessMsg(
        {
            summary: cached.summary,
            key_findings: cached.key_findings,
            recommendations: cached.recommendations,
        },
        false,
        cached.llm_model || 'cached-response',
        null,
    );
    return [msg, null, null];
}

const llmUrl = env.get('AI_INSIGHT_LLM__CHAT_COMPLETIONS_URL') || '';
const llmApiKey = env.get('AI_INSIGHT_LLM__API_KEY') || '';
const llmModel = env.get('AI_INSIGHT_LLM__MODEL') || 'gpt-4.1-mini';
const requireHttps = toBool(env.get('AI_INSIGHT_LLM__REQUIRE_HTTPS'), true);

if (hourlyRowsRaw.length <= 0 || !llmUrl || !llmApiKey || (requireHttps && !String(llmUrl).startsWith('https://'))) {
    makeSuccessMsg(fallbackOutput, false, 'rule-based-fallback', hourlyRowsRaw.length <= 0 ? 'LLM skipped due to insufficient data (rows_analyzed=0)' : 'LLM unavailable');
    return [msg, null, null];
}

msg._energyComputed = {
    context,
    fallbackOutput,
    cacheEnabled,
    cacheKey,
    llmModel,
    cacheBypass,
};
msg.method = 'POST';
msg.url = llmUrl;
msg.headers = {
    'Authorization': `Bearer ${llmApiKey}`,
    'Content-Type': 'application/json',
};
const systemPrompt = [
    'You are an energy and smart-city analytics assistant.',
    'Insight type: Energy trend and 24h forecast. Focus on trend direction, seasonality effects, forecast plausibility, and operational implications.',
    'FACIS domain context:\n- This analysis supports the FACIS demonstrator where simulation-service generates IoT/Smart-City events and related telemetry that are later analyzed in ai-insight-service.\n- Consider data provenance as simulation-backed unless a field indicates otherwise.\n- Keep claims aligned with provided context only; do not invent missing measurements or causes.',
    'Data schema guide:\n- `window`: `{start_ts, end_ts, timezone, rows_analyzed}` for analysis scope.\n- `summary`: compact metrics for quick interpretation.\n- `narrative_hints`: deterministic cues from analytics logic; treat as guidance, not hard facts.\n- Trend/forecast context includes `trend_signals`, `moving_averages`, `seasonality_patterns`, `forecast_24h`, and `data_availability`.',
    'Return ONLY valid JSON, with no markdown and no prose outside JSON.\nRequired top-level object keys (exactly these keys):\n- `summary`: string (2-4 sentences, concise executive overview)\n- `key_findings`: array of strings (3-6 bullets worth of findings, each one sentence)\n- `recommendations`: array of strings (2-5 actionable recommendations, each one sentence)\nConstraints:\n- Do not include additional top-level keys.\n- Preserve factual consistency with provided context.\n- If evidence is insufficient, state uncertainty explicitly in findings/recommendations.'
].join('\n\n');
const userPrompt = 'Analyze the following structured context and produce the required JSON output.\\nContext JSON:\\n' + JSON.stringify(context, null, 2);

msg.payload = {
    model: llmModel,
    temperature: 0.2,
    messages: [
        {
            role: 'system',
            content: systemPrompt,
        },
        {
            role: 'user',
            content: userPrompt,
        }
    ]
};
return [null, null, msg];

const uuidFromMathRandom = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : ((rand & 0x3) | 0x8);
    return value.toString(16);
});
const runtimeCrypto = global.get('crypto');
const makeOutputId = () => (runtimeCrypto && typeof runtimeCrypto.randomUUID === 'function') ? runtimeCrypto.randomUUID() : uuidFromMathRandom();
const computed = msg._energyComputed || {};
const context = computed.context || {};
const fallbackOutput = computed.fallbackOutput || {
    summary: 'Fallback insight generated from deterministic analytics context.',
    key_findings: ['No critical findings were detected for the requested interval.'],
    recommendations: ['Trigger a dashboard refresh once upstream LLM connectivity is restored.']
};

const access = msg.accessContext || {};
const req = msg.energyRequest || {};
const includeData = !!req.include_data;
const isDev = ['development', 'dev', 'local'].includes(String(env.get('AI_INSIGHT_SERVICE__ENVIRONMENT') || env.get('FACIS_ENV') || 'development').toLowerCase());

let finalOutput = fallbackOutput;
let llmUsed = false;
let llmModel = 'rule-based-fallback';
let llmError = null;

if (Number(msg.statusCode || 0) >= 200 && Number(msg.statusCode || 0) < 300) {
    try {
        const payload = msg.payload || {};
        const model = payload.model || computed.llmModel || 'unknown-model';
        const content = payload && payload.choices && payload.choices[0] && payload.choices[0].message && payload.choices[0].message.content;
        let normalized = String(content).trim();
        normalized = normalized.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
        const parsed = JSON.parse(normalized);
        const payloadObj = parsed && (parsed.result || parsed.output || parsed);
        const summaryCandidate = payloadObj && (payloadObj.summary || payloadObj.overview || payloadObj.summary_text);
        const findingsCandidate = payloadObj && (payloadObj.key_findings || payloadObj.keyFindings || payloadObj.findings || payloadObj.keyPoints);
        const recommendationsCandidate = payloadObj && (payloadObj.recommendations || payloadObj.recommendation_list || payloadObj.actions || payloadObj.suggestions);

        const toStringArray = (value) => {
            if (Array.isArray(value)) return value.map((x) => String(x));
            if (typeof value === 'string') {
                return value
                    .split(/\n+/)
                    .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
                    .filter(Boolean);
            }
            if (value && typeof value === 'object') {
                if (Array.isArray(value.items)) return value.items.map((x) => String(x));
                if (Array.isArray(value.points)) return value.points.map((x) => String(x));
                if (Array.isArray(value.list)) return value.list.map((x) => String(x));
            }
            return [];
        };

        const findings = toStringArray(findingsCandidate);
        const recommendations = toStringArray(recommendationsCandidate);
        if (!summaryCandidate || findings.length === 0 || recommendations.length === 0) {
            throw new Error('LLM output does not match expected schema: ' + JSON.stringify(parsed).slice(0, 240));
        }

        finalOutput = {
            summary: String(summaryCandidate),
            key_findings: findings,
            recommendations,
        };
        llmUsed = true;
        llmModel = String(model);
    } catch (error) {
        llmError = String(error && error.message ? error.message : error);
    }
} else {
    llmError = 'LLM request failed with status ' + String(msg.statusCode || 'unknown');
}

if (computed.cacheEnabled && llmUsed && !computed.cacheBypass) {
    const cacheStore = global.get('aiInsightEnergySummaryCache') || {};
    cacheStore[computed.cacheKey] = {
        summary: finalOutput.summary,
        key_findings: finalOutput.key_findings,
        recommendations: finalOutput.recommendations,
        llm_model: llmModel,
        cached_at: new Date().toISOString(),
    };
    global.set('aiInsightEnergySummaryCache', cacheStore);
}

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    insight_type: 'energy-summary',
    summary: finalOutput.summary,
    key_findings: finalOutput.key_findings,
    recommendations: finalOutput.recommendations,
    metadata: {
        output_id: makeOutputId(),
        llm_model: llmModel,
        timestamp: new Date().toISOString(),
        llm_used: llmUsed,
        agreement_id: access.agreement_id || 'unknown-agreement',
        asset_id: access.asset_id || 'unknown-asset',
        llm_error: isDev ? llmError : null,
    },
    data: includeData ? context : null,
};
return [msg, null];

let asObj = msg.payload || {};
try {
    asObj = typeof asObj === 'string' ? JSON.parse(asObj) : asObj;
} catch (_) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Request body must be valid JSON' };
    return [null, msg];
}

if (!asObj || typeof asObj !== 'object') {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Request body must be a JSON object' };
    return [null, msg];
}

const startTs = new Date(asObj.start_ts);
const endTs = new Date(asObj.end_ts);
if (Number.isNaN(startTs.getTime()) || Number.isNaN(endTs.getTime())) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts and end_ts must be valid timestamps' };
    return [null, msg];
}
if (startTs >= endTs) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts must be earlier than end_ts' };
    return [null, msg];
}

const forecastAlpha = asObj.forecast_alpha === undefined ? 0.6 : Number(asObj.forecast_alpha);
if (!Number.isFinite(forecastAlpha) || forecastAlpha <= 0 || forecastAlpha > 1) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'forecast_alpha must be within (0, 1]' };
    return [null, msg];
}

const trendEpsilon = asObj.trend_epsilon === undefined ? 0.02 : Number(asObj.trend_epsilon);
if (!Number.isFinite(trendEpsilon) || trendEpsilon < 0) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'trend_epsilon must be >= 0' };
    return [null, msg];
}

const strategy = asObj.daily_overview_strategy === undefined ? 'strict_daily' : String(asObj.daily_overview_strategy);
if (!['strict_daily', 'fallback_hourly'].includes(strategy)) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'daily_overview_strategy must be strict_daily or fallback_hourly' };
    return [null, msg];
}

msg.energyRequest = {
    start_ts: startTs.toISOString(),
    end_ts: endTs.toISOString(),
    timezone: typeof asObj.timezone === 'string' && asObj.timezone ? asObj.timezone : 'UTC',
    forecast_alpha: forecastAlpha,
    trend_epsilon: trendEpsilon,
    daily_overview_strategy: strategy,
    include_data: !!asObj.include_data,
};

return [msg, null];

const toBool = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const parseList = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    try {
        const parsed = JSON.parse(value);
        if (Array.isArray(parsed)) return parsed.map((item) => String(item));
    } catch (_) {
        // ignore
    }
    return fallback;
};

const headers = (msg.req && msg.req.headers) || {};
const pickHeader = (name) => headers[String(name || '').toLowerCase()];

const policyEnabled = toBool(env.get('AI_INSIGHT_POLICY__ENABLED'), true);
const agreementHeader = env.get('AI_INSIGHT_POLICY__AGREEMENT_HEADER') || 'x-agreement-id';
const assetHeader = env.get('AI_INSIGHT_POLICY__ASSET_HEADER') || 'x-asset-id';
const roleHeader = env.get('AI_INSIGHT_POLICY__ROLE_HEADER') || 'x-user-roles';
const requiredRoles = parseList(env.get('AI_INSIGHT_POLICY__REQUIRED_ROLES'), ['ai_insight_consumer']);
const allowedAgreements = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_AGREEMENT_IDS'), []);
const allowedAssets = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_ASSET_IDS'), []);

const agreementId = String(pickHeader(agreementHeader) || '').trim();
const assetId = String(pickHeader(assetHeader) || '').trim();
const rawRoles = String(pickHeader(roleHeader) || '').trim();
const roles = rawRoles ? rawRoles.split(',').map((item) => item.trim()).filter(Boolean) : [];

if (policyEnabled) {
    if (!agreementId || !assetId || roles.length === 0) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Missing required governance headers' };
        return [null, msg, null];
    }

    const missingRole = requiredRoles.find((role) => !roles.includes(role));
    if (missingRole) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied: missing required role ' + missingRole };
        return [null, msg, null];
    }

    if (allowedAgreements.length > 0 && !allowedAgreements.includes(agreementId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for agreement_id' };
        return [null, msg, null];
    }

    if (allowedAssets.length > 0 && !allowedAssets.includes(assetId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for asset_id' };
        return [null, msg, null];
    }
}

const rateLimitEnabled = toBool(env.get('AI_INSIGHT_RATE_LIMIT__ENABLED'), true);
const rpm = Math.max(1, Number(env.get('AI_INSIGHT_RATE_LIMIT__REQUESTS_PER_MINUTE') || 10));
const limiterAgreement = agreementId || 'anonymous';

if (rateLimitEnabled) {
    const bucketKey = 'aiInsightRateLimitBuckets';
    const buckets = global.get(bucketKey) || {};
    const now = Date.now();
    const windowMs = 60 * 1000;
    let bucket = buckets[limiterAgreement];
    if (!bucket || now - bucket.windowStart >= windowMs) {
        bucket = { windowStart: now, count: 0 };
    }
    if (bucket.count >= rpm) {
        const retryAfter = Math.max(1, Math.ceil((bucket.windowStart + windowMs - now) / 1000));
        msg.statusCode = 429;
        msg.headers = {
            'Content-Type': 'application/json',
            'Retry-After': String(retryAfter),
        };
        msg.payload = { detail: 'Agreement rate limit exceeded' };
        buckets[limiterAgreement] = bucket;
        global.set(bucketKey, buckets);
        return [null, null, msg];
    }
    bucket.count += 1;
    buckets[limiterAgreement] = bucket;
    global.set(bucketKey, buckets);
}

msg.accessContext = {
    agreement_id: agreementId || 'unknown-agreement',
    asset_id: assetId || 'unknown-asset',
    roles,
};

return [msg, null, null];

const latest = global.get('aiInsightLatestOutputs') || {};
const outputsById = global.get('aiInsightOutputsById') || {};
if (msg && msg.payload && msg.payload.metadata) {
    const snapshot = JSON.parse(JSON.stringify(msg.payload));
    const metadata = snapshot.metadata || {};
    const outputId = String(metadata.output_id || '').trim();

    latest['energy-summary'] = {
        cached_at: metadata.timestamp || new Date().toISOString(),
        output: snapshot,
    };
    global.set('aiInsightLatestOutputs', latest);

    const fallbackText = [
        String(snapshot.summary || ''),
        ...((Array.isArray(snapshot.key_findings) ? snapshot.key_findings : []).map((item) => '- ' + String(item))),
        ...((Array.isArray(snapshot.recommendations) ? snapshot.recommendations : []).map((item) => '- ' + String(item))),
    ].filter((line) => String(line).trim().length > 0).join('\n');

    if (outputId) {
        outputsById[outputId] = {
            id: outputId,
            insight_type: 'energy-summary',
            agreement_id: String(metadata.agreement_id || 'unknown-agreement'),
            asset_id: String(metadata.asset_id || 'unknown-asset'),
            input_data: JSON.parse(JSON.stringify(msg.energyRequest || {})),
            llm_model: String(metadata.llm_model || 'rule-based-fallback'),
            output_text: (typeof msg._llmRawText === 'string' && msg._llmRawText.trim()) ? msg._llmRawText.trim() : fallbackText,
            structured_output: {
                summary: String(snapshot.summary || ''),
                key_findings: Array.isArray(snapshot.key_findings) ? snapshot.key_findings.map((item) => String(item)) : [],
                recommendations: Array.isArray(snapshot.recommendations) ? snapshot.recommendations.map((item) => String(item)) : [],
            },
            timestamp: String(metadata.timestamp || new Date().toISOString()),
        };
        global.set('aiInsightOutputsById', outputsById);
    }
}
return msg;

if (msg._energyResponseDispatched) {
    return null;
}
msg._energyResponseDispatched = true;

const detail = (msg.payload && msg.payload.detail)
    ? String(msg.payload.detail)
    : 'Upstream dependency failure while generating insight';

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail
};

return msg;

const sourceId = msg.error && msg.error.source && msg.error.source.id;
if (sourceId === 'http_resp_energy_502_json') {
    return null;
}

if (!msg.res) {
    return null;
}

const alreadySent = !!(msg.res.headersSent || (msg.res._res && (msg.res._res.headersSent || msg.res._res.writableEnded)));
if (alreadySent) {
    return null;
}

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail: 'Upstream dependency failure while generating insight'
};
return msg;
